    {
        return await _context.Estimates.FindAsync(id);
    }

    public async Task CreateEstimateAsync(Estimate estimate)
    {
        _context.Estimates.Add(estimate);
        await _context.SaveChangesAsync();
    }

    public async Task UpdateEstimateAsync(Estimate estimate)
    {
        _context.Estimates.Update(estimate);
        await _context.SaveChangesAsync();
    }

    public async Task DeleteEstimateAsync(int id)
    {
        var estimate = await _context.Estimates.FindAsync(id);
        if (estimate != null)
        {
            _context.Estimates.Remove(estimate);
            await _context.SaveChangesAsync();
        }
    }
}
