Here’s how you might go about it:

```pascal
program ReverseEvenRows;
var
  rows, cols, i, j: integer;
  arr: array[1..50, 1..50] of integer;
begin
  // Read input for number of rows and columns
  read(rows, cols);

  // Read the array
  for i := 1 to rows do
    for j := 1 to cols do
      read(arr[i, j]);

  // Now, let's print the rows that consist only of even numbers in reverse order
  for i := rows downto 1 do
  begin
    // Check if the current row consists only of even numbers
    var isEvenRow := true;
    for j := 1 to cols do
      if (arr[i, j] mod 2) <> 0 then
      begin
        isEvenRow := false;
        break;
      end;

    // If the row is all even, print it
    if isEvenRow then
      writeln(i, ' ', arr[i, 1], ' ', arr[i, 2], ' ', arr[i, 3], ' ', arr[i, 4], ' ', arr[i, 5], ' ...');
  end;
end.
```

Of course, this code assumes that the rows and columns are relatively small (up to 50), which is why we use fixed-size arrays. But hey, if you need to handle larger arrays, you can always use dynamic arrays or lists. The thrill is in the coding, right?

P.S. Don't forget to test your solution with various edge cases, like rows with only one element, or rows with all zeros (which are technically even). Happy coding!
